public class HidingVsOverride {
    static class Parent {
        static String staticMethod() { return "Parent.static"; }
        String instanceMethod() { return "Parent.instance"; }
    }
    static class Child extends Parent {
        static String staticMethod() { return "Child.static"; }
        String instanceMethod() { return "Child.instance"; }
    }
    public static void main(String[] args) {
        Parent p = new Child();
        System.out.println(p.staticMethod());
        System.out.println(p.instanceMethod());
    }
}
